# planning/capacity.py
# Compute quarterly capacity envelope and score candidate epics.

from dataclasses import dataclass
from typing import Literal

@dataclass
class Engineer:
    name: str
    weeks_available: int   # quarter weeks minus PTO and on-call rotation

@dataclass
class CandidateEpic:
    id: str
    title: str
    category: Literal["new-capability", "reliability", "tech-debt", "security"]
    okr_refs: list[str]
    effort_weeks: int      # 1 = one engineer-week
    impact_score: int      # 1–5: estimated improvement to a KR
    reach_score:  int      # 1–5: how many teams benefit directly
    # signal: optional friction item ID or RFC ID

    @property
    def priority_score(self) -> float:
        # Simple RICE-derived formula; adjust weights as needed.
        return (self.impact_score * self.reach_score) / max(self.effort_weeks, 1)

# Budget allocation ratios
BUDGET = {
    "new-capability": 0.45,
    "reliability":    0.25,
    "tech-debt":      0.20,
    "security":       0.10,   # reserve; unspent rolls forward
}

def plan_quarter(engineers: list[Engineer], candidates: list[CandidateEpic]):
    total_eng_weeks = sum(e.weeks_available for e in engineers)
    envelope = {cat: int(total_eng_weeks * ratio) for cat, ratio in BUDGET.items()}

    committed, deferred = [], []
    remaining = dict(envelope)

    for cat in ["security", "reliability", "new-capability", "tech-debt"]:
        cat_epics = sorted(
            [e for e in candidates if e.category == cat],
            key=lambda e: e.priority_score,
            reverse=True,
        )
        for epic in cat_epics:
            if remaining[cat] >= epic.effort_weeks:
                committed.append(epic)
                remaining[cat] -= epic.effort_weeks
            else:
                deferred.append(epic)

    return committed, deferred, envelope, remaining

# Usage
engineers = [
    Engineer("alice", 10),
    Engineer("bob",   11),
    Engineer("carol",  9),
]
committed, deferred, envelope, remaining = plan_quarter(engineers, candidate_epics)
print(f"Total capacity: {sum(e.weeks_available for e in engineers)} eng-weeks")
for cat, weeks in envelope.items():
    print(f"  {cat}: {weeks} weeks budgeted, {remaining[cat]} remaining")
